INSERT INTO blog_post_faqs (blog_post_id, question, answer, position) VALUES 
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Puis-je poser une UE sur mon balcon sans vote ?', 'Dès qu''il y a percement ou impact sur façades/parties communes, une autorisation est en général nécessaire. Le balcon lui-même peut être partie commune à usage privatif : vérifiez le règlement.', 1),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Le syndic refuse pour le bruit : que faire ?', 'Améliorer l''implantation (orientation, dégagement), ajouter silentblocs/châssis et écran absorbant, programmer un mode nuit. Un photomontage et une note d''un pro aident souvent.', 2),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Les "coffres design" du commerce suffisent-ils ?', 'Certains enferment l''UE et la font forcer (plus de bruit, moins de perf). Préférez un écran absorbant ventilé et dimensionné.', 3),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Faut-il une mesure acoustique officielle ?', 'Pas toujours. Une appli donne une tendance ; pour un dossier sensible, faites mesurer par un pro ou citez les niveaux constructeurs + vos mesures simples.', 4),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Que risque-t-on sans autorisation ?', 'Mise en conformité exigée (jusqu''à dépose), conflit de voisinage, difficulté en cas de revente. Mieux vaut faire valider proprement.', 5),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Et l''hiver, ça chauffe ?', 'La clim réversible chauffe en mi-saison ; par grand froid, c''est un appoint. Pour le chauffage principal d''un appart, on étudie d''autres systèmes.', 6),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Quid des odeurs et de la qualité d''air ?', 'Entretien régulier (filtres, désinfection) = air sain, pas d''odeurs. On peut ajouter des filtres renforcés pour allergiques.', 7),
('2d23cef2-c1f2-4a1b-9b9e-e183579334ae', 'Combien de temps pour tout boucler ?', 'Souvent 2 à 8 semaines selon la date d''AG, l''approvisionnement et le planning d''installation.', 8);